export interface Service {
  slug: string;
  title: string;
  subtitle: string;
  description: string;
  longDescription: string;
  ideal: string[];
  category: "light-duty" | "heavy-duty" | "roadside" | "specialty" | "commercial";
  commonCauses: string[];
  whatToDo: string[];
  whatWeBring: string[];
  commonMistakes: string[];
  pricingNotes: string;
  nycSpecifics: string[];
  relatedServices: string[];
  idealCustomerContext: string;
  neighborhoodContext: string;
}

/** Generate extended SEO content for a service page (~4,500 words) */
export function getExtendedContent(service: Service): string[] {
  const t = service.title;
  const tl = service.title.toLowerCase();
  const cat = SERVICE_CATEGORIES[service.category];

  // Resolve related service titles for inline mention
  const relatedTitles = service.relatedServices
    .map((slug) => SERVICES.find((s) => s.slug === slug)?.title)
    .filter((x): x is string => !!x);
  const relatedCsv = relatedTitles.slice(0, 4).join(", ");

  const causes = service.commonCauses;
  const todo = service.whatToDo;
  const bring = service.whatWeBring;
  const mistakes = service.commonMistakes;
  const nyc = service.nycSpecifics;

  return [
    // ========== INTRO ==========
    `${t} is one of ${SERVICES.length} services The NYC Towing Service runs across Manhattan, Brooklyn, Queens, the Bronx, and Staten Island, and inside the ${cat.label.toLowerCase()} category it is one of the calls we handle most. ${service.longDescription} The reason a dedicated ${tl} line exists — instead of folding the work into a generic tow call — is that the failure mode, the gear, the on-scene procedure, and the NYC-specific hazards are all different. A dispatcher who runs ${tl} every day knows which truck to send, which bridge to avoid, which neighborhood tends to generate this call, and how to price it without surprising the customer at the curb.`,

    `New York runs ${tl} differently than the suburbs for a reason. The street grid is narrow, the curb is always contested, alt-side-parking enforcement turns every Tuesday into a game of musical chairs, and weather swings from 95-degree July humidity to a 12-degree February wind chill that kills marginal batteries in their sleep. A suburban operator from Westchester or Nassau who rolls a truck into the city without local knowledge loses an hour just to routing — the ${tl} call that should take 25 minutes becomes a 90-minute call, and the customer eats the lost time in billable minutes or worse, a missed window for a tow to a body shop that closes at 5. Our ${tl} team is staged across the five boroughs on purpose, so we are never the long-haul operator on your job.`,

    // ========== WHY THIS HAPPENS IN NYC ==========
    `Why does ${tl} happen as often as it does in New York? The short answer is density and stress. With roughly 1.4 million registered passenger vehicles plus the daily inflow of delivery trucks, rideshare drivers, out-of-borough commuters, and commercial fleets, the city generates more mechanical events per square mile than almost anywhere else in the country. The long answer is specific to this service. ${causes[0] ?? ""} is the single most common cause we see — it shows up on dispatch logs week after week and accounts for a meaningful share of our ${tl} volume.`,

    `${causes[1] ?? ""} is the second pattern we see repeatedly. It tends to hit during specific weather windows or in specific neighborhoods, and it is one of the reasons we stage trucks the way we do. If you have been driving in NYC for more than a year, you have probably either experienced this yourself or watched a neighbor experience it. The difference between "annoying hour" and "ruined day" is almost always how fast the help arrived and whether the operator understood what they were looking at.`,

    `${causes[2] ?? ""} is another major contributor. New Yorkers who park on the street long-term see this more than garage parkers, and drivers who commute into Manhattan from the outer boroughs see a different flavor of it. ${causes[3] ?? ""} shows up in our logs too — less common than the first two, but when it happens it almost always generates a ${tl} call because the vehicle is genuinely not drivable. ${causes[4] ?? ""} rounds out the top five. Each of these causes maps to a different on-scene procedure, which is why one-size-fits-all tow operators tend to show up with the wrong truck.`,

    `Borough by borough, the causes tilt differently. Manhattan's mid- and high-rise garage population insulates a lot of vehicles from weather-driven failures, but the curbside-parked vehicles on the Upper East Side, Upper West Side, West Village, and East Village see all of it. Brooklyn's mix of brownstone blocks, commercial corridors, and the Belt Parkway shoulder generates a specific pattern — a lot of overnight-park failures in Park Slope, Williamsburg, Bushwick, and Bay Ridge, and a lot of highway-shoulder calls on the Belt and the BQE. Queens is the highest-volume borough for our ${tl} line overall, with the 6.7-mile Cross Island Parkway, the LIE, Grand Central Parkway, and the JFK and LaGuardia approach roads all feeding calls. The Bronx's elevated highways (Cross Bronx, Major Deegan, Bruckner) and Staten Island's hills plus the West Shore and Staten Island Expressway corridors each produce their own patterns.`,

    // ========== WHAT TO DO RIGHT NOW ==========
    `If ${tl} is happening to you right now, the first thing to do is ${todo[0]?.toLowerCase() ?? "get the vehicle to a safe position and stop driving"}. Do not try to push through — whatever is wrong, driving on it compounds the damage and often turns a roadside fix into a full tow plus shop time. Get to the safest position you can reach in the next 30 seconds and stop. If you are in a travel lane on the BQE, the LIE, the FDR, the Cross Bronx, the West Side Highway, or any parkway, the shoulder is your goal. If no shoulder exists, call 911 first — NYPD and the NYC Department of Transportation have protocols for exactly this situation, and they need to manage the scene before any tow operator is allowed to work it safely.`,

    `Second, ${todo[1]?.toLowerCase() ?? "turn on the hazard lights and set out a reflective triangle if you have one"}. Hazard lights reduce the probability of a secondary collision by a meaningful margin, and on NYC highways where closing speeds in the left lane are 60+ mph, that margin matters. If you do not have a reflective triangle or cones, stand at the rear corner of the vehicle on the curb side and wave traffic around — do not stand between the vehicle and oncoming traffic, ever. Keep passengers out of the vehicle if you are on a highway; keep passengers inside the vehicle with seatbelts on if you are on a low-speed side street.`,

    `Third, ${todo[2]?.toLowerCase() ?? "call dispatch at (212) 470-4068 and describe what you are seeing"}. The more specific you are, the faster the right truck and right tools get to you. "I'm on the BQE northbound near Atlantic Avenue and the engine died" is useful. "I'm somewhere in Brooklyn and the car won't go" costs the dispatcher 60 seconds of clarifying questions. Give cross streets, the mile marker if you see one, what you were doing when the failure happened, and whether any warning lights are on the dashboard. The dispatcher will read back a truck number, driver name, and ETA before ending the call.`,

    `Fourth, ${todo[3]?.toLowerCase() ?? "gather your documentation"}. Driver's license, registration, insurance card, and payment method. If this is a commercial vehicle, also pull the DOT number, company name, and fleet contact. If it is an insurance tow, find the claim number and the adjuster's contact. Getting these ready before the truck arrives shaves minutes off the handoff and makes the invoice cleaner. Fifth, ${todo[4]?.toLowerCase() ?? "do not attempt DIY fixes that make things worse"}. ${todo[5] ?? "Stay with the vehicle until the driver arrives so the driver can confirm the match."}`,

    `A note on bystander "help" in NYC: if a stranger pulls over and offers to jump your battery, plug your tire, unlock your door, or push you out of a snowbank, default to a polite no. The city has a persistent low-grade problem with bad-faith roadside actors — people who offer a "quick fix" that turns into a demanded cash payment, or worse, a setup for theft. Professional operators have marked trucks, uniforms, a dispatcher on the phone who can confirm our arrival, and licensing that we will show you on request. If someone pulls up without credentials, keep your doors locked, tell them help is already on the way, and stay put.`,

    // ========== WHAT WE BRING ==========
    `When we roll a ${tl} call, the truck arrives loaded with the specific gear the job needs — not a generic kit. ${bring[0] ?? ""} is the first item, and it is the one that actually solves the primary problem on most calls. We maintain it in working condition and test it before every shift because a dead battery in a jump-starter or a dry tank on a fuel delivery truck would make the whole trip a waste of everyone's time.`,

    `${bring[1] ?? ""} backs up the primary tool, and ${bring[2] ?? ""} handles the secondary situations that turn up on maybe one call in five. Experienced drivers know that the phoned-in description is not always what we find on scene — "dead battery" sometimes turns out to be a bad starter, "flat tire" sometimes turns out to be a broken control arm, "locked out" sometimes turns out to be a dead key fob. The second and third items in the truck's kit cover those cases so the driver does not have to radio dispatch and wait for a second truck with different gear.`,

    `${bring[3] ?? ""} and ${bring[4] ?? ""} round out the kit for common variations. For ${tl} specifically, the toolkit also includes wheel chocks that hold on a steep NYC grade (every driver has stories from the hills in Riverdale, Kingsbridge, Washington Heights, Staten Island's Todt Hill, and Brooklyn's Park Slope), reflective cones and triangles for scene protection on high-speed roads, and work lights for overnight calls where streetlights do not cover the shoulder you are stuck on.`,

    `Every truck in our ${tl} fleet also carries documentation gear — a phone mount, a dash camera, and a digital intake pad for photos and the customer's signature at completion. We photograph the vehicle before we touch it, during the procedure, and after. Those photos live in your service record for 90 days and are available on request if your insurance adjuster, body shop, or attorney needs them. For fleet accounts, condition-report photos are pushed to your fleet portal automatically before the truck leaves the scene.`,

    // ========== COMMON MISTAKES ==========
    `The most common mistake we see on ${tl} calls is ${mistakes[0]?.toLowerCase() ?? "waiting too long to call"}. Drivers convince themselves the problem will sort itself out, they try to nurse the vehicle to a "safer" spot and make it worse, or they spend 40 minutes trying to DIY a fix before picking up the phone. The city does not reward that patience — parking enforcement, NYPD towing of vehicles in travel lanes, theft from stationary vehicles, and the risk of a secondary collision all scale with time. Calling us at minute 2 instead of minute 42 changes the whole shape of the call.`,

    `The second most common mistake is ${mistakes[1]?.toLowerCase() ?? "accepting help from unmarked trucks that just happened to be passing"}. The city has a persistent pattern of unlicensed operators who listen to police scanners and show up at breakdown scenes to pitch an inflated cash-only service. Real operators have truck numbers, dispatcher confirmation, licensing we can produce on request, and a paper trail. If a truck shows up that you did not call, does not match the one dispatch described, or does not have credentials, keep your doors locked and call dispatch back to confirm.`,

    `Third, ${mistakes[2]?.toLowerCase() ?? "don't sign anything before the work is done and the price matches what dispatch quoted"}. Flat-rate is flat-rate. The number the dispatcher quotes on the phone is the number on the invoice unless the scope materially changes, in which case the driver will stop and walk you through the revised quote before proceeding. Fourth, ${mistakes[3]?.toLowerCase() ?? "don't refuse documentation"}. We take photos because they protect both of us. Refusing the photo walkthrough almost always signals a customer who is planning to dispute the charge later, and it makes the driver's job harder. It also means no receipt for insurance.`,

    `Fifth, ${mistakes[4] ?? "don't leave the vehicle unattended if you can help it."} A locked vehicle on an NYC curb with hazards on is a theft risk — not because NYC is particularly dangerous but because "hazards on, unattended" reads as "opportunity" to the small number of people who work that opportunity. Sit inside with the doors locked if it is safe to do so, or stay within visual range of the vehicle until the driver arrives.`,

    // ========== PRICING ==========
    `Pricing for ${tl} in NYC is flat-rate, quoted on the phone before we dispatch, and matched at the invoice. ${service.pricingNotes} The one thing that does vary is scope — if we arrive and the situation is materially different from what was described, the driver stops and rebuilds the quote with you before doing the work. "Materially different" means the vehicle turned out to be an AWD when the phone call described it as FWD, or the "flat tire" turned out to be a blown-out sidewall that needs flatbed instead of curbside plug, or the "dead battery" is actually a bad alternator and we need to tow to a shop instead of just jumping. Honest rebuild, itemized.`,

    `What affects the flat rate: the type of truck (wheel-lift vs flatbed vs heavy-duty), the distance of the tow (first five miles are included, per-mile beyond), the time of day only for specific calls where the scope legitimately requires overnight or holiday rigging (we do not charge an "after-hours surcharge" just for being awake — that is a national-dispatcher trick), and the specific procedure on the job. We itemize all of it on the invoice. For insurance claim tows we bill the carrier directly where the policy covers it and you pay zero out of pocket.`,

    `Methods of payment accepted: every major credit card, Apple Pay, Google Pay, Zelle for established customers, and cash. Receipts are emailed within minutes of completion — the driver sends it before leaving the scene. For fleet accounts we bill net-30 on a consolidated monthly invoice. For insurance claim tows we have direct-bill relationships with Geico, State Farm, Allstate, Progressive, USAA, Liberty Mutual, Farmers, Nationwide, Travelers, and most regional carriers. If your carrier is not on that list we can still help — we collect up front, provide a detailed receipt, and most carriers reimburse on submission.`,

    // ========== HOW THE CALL GOES ==========
    `Here is how a ${tl} call goes from start to finish. Minute zero, you call (212) 470-4068. The dispatcher who answers is the dispatcher who is going to route your truck — not a call center in another state, not an answering service, not a voicemail. In 60-90 seconds we confirm your location (address or cross-streets, the latter works fine), what is wrong with the vehicle, year/make/model, and where it needs to go after service.`,

    `Minute 2, dispatch selects a truck. The selection is based on three variables: which truck is closest to you, which truck has the right gear for ${tl} specifically, and which driver has the most experience with your vehicle class. For luxury, exotic, EV, AWD, and motorcycle calls, the selection is tighter because a generalist wheel-lift driver is the wrong call. Dispatch reads you the truck number, driver name, and ETA before ending the call. If traffic has shifted the ETA while you were on the phone, we tell you.`,

    `Minute 15-30 (typical window, longer during snow events and major traffic disruptions), the truck arrives. The driver pulls up, confirms your identity and the vehicle, and walks the vehicle with you to document condition. Date-stamped photos go into your service record. The driver explains exactly what is about to happen — which tool is going to touch the vehicle, what the expected outcome is, and what could change the scope mid-job.`,

    `Minutes 30-60, the work happens. For most ${tl} calls, the on-scene work is 15-30 minutes. For tows, we load, tie down, and route to the destination. For roadside procedures (battery, tire, lockout, gas), we complete the procedure, confirm the fix, and run a quick post-service check — for example, on battery jumps we verify the alternator is charging before we leave, so you do not run ten miles and stall. At completion, payment processes on the spot, the receipt emails to you, and the service report closes in our system.`,

    `End of call, you have a paid invoice in your email, a full photo record in your service history, and the vehicle at its destination or back in working order. If any follow-up is needed — warranty claim on parts we installed, disputed charge, insurance paperwork, lost receipt — you call the same dispatch number. We do not offshore support. The operator who took your call can pull your ticket and answer questions from the same screen.`,

    // ========== NYC SPECIFICS ==========
    `A few NYC-specific things about ${tl} that national operators miss. ${nyc[0] ?? ""} — that is the kind of detail a suburban dispatcher does not know and a local driver knows in their sleep. It changes the routing, the gear loadout, and sometimes the drop-off destination.`,

    `${nyc[1] ?? ""} is another one we plan around. NYC's bridge and tunnel network shapes every route — the Verrazzano, the Brooklyn Bridge, the Manhattan Bridge, the Williamsburg Bridge, the Queensboro, the Triboro/RFK, the GWB, the Lincoln, the Holland, the Midtown Tunnel, the Brooklyn-Battery/Hugh Carey — each has its own clearance, toll, traffic pattern, and breakdown-response protocol. A driver who takes the wrong crossing loses 20 minutes. A driver who does not know that the Holland Tunnel has no shoulder loses the whole call if a breakdown happens on the wrong side.`,

    `${nyc[2] ?? ""} also shows up repeatedly. If you live or work in NYC, you know alternate-side parking is not a suggestion — it is a tool the city uses to keep the curb moving and the street-sweepers productive. On ${tl} calls, alt-side enforcement creates two patterns: the "plowed-in on alt-side-suspended day" pattern and the "dispatch window has to finish before the 8:30 AM street-sweeper arrives" pattern. Our dispatchers watch the city's alt-side calendar and route accordingly.`,

    `${nyc[3] ?? ""} rounds out the NYC-specific awareness. ${nyc[4] ?? ""} NYC's five boroughs each have their own personality, their own call patterns, and their own geography. Manhattan's vertical density and garage population, Brooklyn's brownstone curbs and waterfront industrial corridors, Queens's wide-open parkway system, the Bronx's elevated highway grid, and Staten Island's suburban-leaning street network — each one calls for a slightly different playbook on ${tl}, and the dispatcher who takes your call knows which playbook to run.`,

    `Weather overlays the whole thing. NYC's freeze-thaw cycle between November and March is brutal on batteries, tires, and cooling systems. The summer's 90-degree humidity turns a marginal radiator into a roadside boil-over. Nor'easters stall traffic for hours and create the "stuck in a snowbank" calls we run through March. Our ${tl} operation is sized for all of that — we do not reduce staffing in winter or bet on "quiet" weekends. The dispatch line is staffed 24/7, every day, every holiday.`,

    // ========== RELATED SERVICES ==========
    `${t} frequently dovetails with other services we run. ${relatedCsv ? `The most common crossovers are ${relatedCsv}.` : ""} If you call us for one and the situation turns out to be the other, dispatch re-routes on the same phone call — you do not have to hang up and start over. For example, a ${tl} call that turns into a tow is handled without a second intake. A call that starts as one service and turns out to need a different truck gets the right truck dispatched with the original service fee credited toward the new job.`,

    `Drivers in our fleet cross-train on adjacent services. A driver staged for ${tl} can handle the top one or two related calls on the same truck for most scenarios, which is how we keep ETAs tight. For calls that genuinely need a specialized truck (heavy-duty, low-angle flatbed for exotics, enclosed trailer for classics), we dispatch the right equipment and coordinate the handoff so the customer is not left waiting for a second truck on an open block.`,

    // ========== IDEAL CUSTOMER ==========
    `${service.idealCustomerContext} The profile we see most often is someone who did not plan to need this service today, whose day has already gone sideways, and who needs a clean, fast, non-dramatic resolution so they can get back to whatever they were supposed to be doing. We optimize the whole operation for that — short phone intake, fast dispatch, honest pricing, competent drivers, zero upsell pressure.`,

    `The second profile is repeat customers and accounts — fleet managers, body shops, property managers, insurance adjusters, dealerships — for whom this is a recurring operational need and the question is not "is there a tow operator" but "is there a tow operator who documents cleanly, bills predictably, and shows up on time every time." We are built for both profiles. The individual stranded driver gets the same priority routing as the fleet account; the fleet account gets the consolidated invoicing and dedicated account manager that individual callers do not need.`,
  ];
}

